"""matplotlib.patheffects — path effect stubs."""


class AbstractPathEffect:
    def __init__(self, offset=(0, 0)):
        self._offset = offset

    def draw_path(self, renderer, gc, tpath, affine, rgbFace=None):
        pass


class Normal(AbstractPathEffect):
    pass


class Stroke(AbstractPathEffect):
    def __init__(self, offset=(0, 0), **kwargs):
        super().__init__(offset)
        self._gc = kwargs


class SimplePatchShadow(AbstractPathEffect):
    def __init__(self, offset=(2, -2), shadow_rgbFace=None, alpha=None, rho=0.3, **kwargs):
        super().__init__(offset)
        self.shadow_rgbFace = shadow_rgbFace
        self.alpha = alpha
        self.rho = rho


class SimpleLineShadow(AbstractPathEffect):
    def __init__(self, offset=(2, -2), shadow_color='k', alpha=0.3, rho=0.3, **kwargs):
        super().__init__(offset)
        self.shadow_color = shadow_color
        self.alpha = alpha


class PathPatchEffect(AbstractPathEffect):
    def __init__(self, offset=(0, 0), **kwargs):
        super().__init__(offset)
        self._props = kwargs


class withStroke(Stroke):
    pass


class withSimplePatchShadow(SimplePatchShadow):
    pass


class TickedStroke(AbstractPathEffect):
    def __init__(self, offset=(0, 0), spacing=10.0, angle=45.0, length=1.414, **kwargs):
        super().__init__(offset)
        self.spacing = spacing
        self.angle = angle
        self.length = length
